function WikiImage({ title, alt, className = "" }: { title: string; alt: string; className?: string }) {
  const [src, setSrc] = useState("");
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    let cancelled = false;
    setSrc("");
    setFailed(false);

    fetch(`https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(title)}`)
      .then((res) => {
        if (!res.ok) throw new Error("Image request failed");
        return res.json();
      })
      .then((data) => {
        if (!cancelled) {
          const image = data?.thumbnail?.source || data?.originalimage?.source || "";
          if (image) setSrc(image);
          else setFailed(true);
        }
      })
      .catch(() => !cancelled && setFailed(true));

    return () => { cancelled = true; };
  }, [title]);

  if (!src || failed) {
    return (
      <div className={`animal-image-fallback ${className}`} role="img" aria-label={alt}>
        <span>🦁</span>
      </div>
    );
  }

  return <img className={className} loading="lazy" src={src} alt={alt} onError={() => setFailed(true)} />;
}

function speak(text: string) {
  if (typeof window === "undefined") return;
  window.speechSynthesis.cancel();
  const u = new SpeechSynthesisUtterance(text);
  u.lang = "fr-FR";
  u.rate = 0.86;
  window.speechSynthesis.speak(u);
}

